import{_ as i,c as a,o as s,a2 as t}from"./chunks/framework.CIiVzG-O.js";const m=JSON.parse('{"title":"Screen Recording Permission Guide (macOS)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/screen-recording.md","filePath":"guide/screen-recording.md","lastUpdated":1776396452000}'),r={name:"guide/screen-recording.md"};function n(o,e,c,l,p,d){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="screen-recording-permission-guide-macos" tabindex="-1">Screen Recording Permission Guide (macOS) <a class="header-anchor" href="#screen-recording-permission-guide-macos" aria-label="Permalink to &quot;Screen Recording Permission Guide (macOS)&quot;">​</a></h1><h2 id="why-does-nicasa-need-screen-recording-permission" tabindex="-1">Why Does Nicasa Need Screen Recording Permission? <a class="header-anchor" href="#why-does-nicasa-need-screen-recording-permission" aria-label="Permalink to &quot;Why Does Nicasa Need Screen Recording Permission?&quot;">​</a></h2><p>On macOS, screenshot and screen capture applications must be granted Screen Recording permission in order to read pixels from the display.</p><p>Starting from macOS 10.15 Catalina, Apple introduced stricter privacy protections. Any application that captures screen content — including screenshots — must be explicitly approved by the user.</p><p>This applies to all apps, including those downloaded from the Mac App Store.</p><p><strong>Without this permission, Nicasa cannot capture screenshots or record screen content.</strong></p><h2 id="how-to-enable-screen-recording-permission" tabindex="-1">How to Enable Screen Recording Permission <a class="header-anchor" href="#how-to-enable-screen-recording-permission" aria-label="Permalink to &quot;How to Enable Screen Recording Permission&quot;">​</a></h2><p>Follow these steps:</p><ol><li>Open <strong>System Settings</strong></li><li>Go to <strong>Privacy &amp; Security</strong></li><li>Select <strong>Screen Recording</strong></li><li>Find <strong>Nicasa</strong> in the list and check the box</li></ol><p>If the app was already running, restart Nicasa after enabling the permission.</p><h2 id="if-the-permission-prompt-did-not-appear" tabindex="-1">If the Permission Prompt Did Not Appear <a class="header-anchor" href="#if-the-permission-prompt-did-not-appear" aria-label="Permalink to &quot;If the Permission Prompt Did Not Appear&quot;">​</a></h2><p>The permission dialog usually appears the first time the app attempts to capture the screen.</p><p>If you did not see the prompt, it may be because:</p><ul><li>The permission request was previously denied</li><li>The permission state is cached by macOS</li><li>The app attempted capture before the dialog could appear</li></ul><p>In this case, you may need to reset the permission.</p><h2 id="reset-screen-recording-permission" tabindex="-1">Reset Screen Recording Permission <a class="header-anchor" href="#reset-screen-recording-permission" aria-label="Permalink to &quot;Reset Screen Recording Permission&quot;">​</a></h2><p>You can reset the permission using the following command in Terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ScreenCapture</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> com.nicasa.nue</span></span></code></pre></div><p>After running the command:</p><ol><li>Restart Nicasa</li><li>Trigger the screenshot feature again</li><li>macOS should display the permission dialog again</li></ol><h2 id="if-reset-still-does-not-work" tabindex="-1">If Reset Still Does Not Work <a class="header-anchor" href="#if-reset-still-does-not-work" aria-label="Permalink to &quot;If Reset Still Does Not Work&quot;">​</a></h2><p>In rare cases, macOS may keep an invalid permission state.</p><p>If resetting the permission does not resolve the issue, try the following steps:</p><ol><li>Quit Nicasa</li><li>Delete Nicasa from your Applications folder</li><li>Reinstall the latest version from the Mac App Store</li><li>Launch the app again</li><li>When macOS asks for Screen Recording permission, select <strong>Allow</strong></li></ol><p>Reinstalling the app can force macOS to recreate the permission entry.</p><h2 id="alternative-manual-fix" tabindex="-1">Alternative Manual Fix <a class="header-anchor" href="#alternative-manual-fix" aria-label="Permalink to &quot;Alternative Manual Fix&quot;">​</a></h2><p>You can also manually toggle the permission:</p><ol><li>Open <strong>System Settings</strong></li><li>Go to <strong>Privacy &amp; Security</strong></li><li>Open <strong>Screen Recording</strong></li><li>Uncheck Nicasa, then check it again</li><li>Restart Nicasa</li></ol><h2 id="security-note" tabindex="-1">Security Note <a class="header-anchor" href="#security-note" aria-label="Permalink to &quot;Security Note&quot;">​</a></h2><p>Granting Screen Recording permission does not allow Nicasa to control your system.</p><p>It only allows the application to capture screen pixels for screenshot and capture features.</p><p>You can revoke this permission at any time in: <strong>System Settings → Privacy &amp; Security → Screen Recording</strong></p>',32)])])}const g=i(r,[["render",n]]);export{m as __pageData,g as default};
